            sh:sourceShape _:n03c85e6c2c8a4b0994f1b377717657aeb3 ;
            sh:value <https://example.org/concept/FR> ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/concept-scheme/iso3166-eu> ;
            sh:resultMessage "schema:identifier is required on a CDIF codelist (string or PropertyValue)." ;
